(()=>{'use strict';
const DEFAULT_URL='https://saodmeoilixfdqentofp.supabase.co';
const PUBLIC_ACTIVE_ENDPOINT='https://saodmeoilixfdqentofp.supabase.co/functions/v1/doit-active';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim();
let active=null,loading=false,publicPacket=null,sourceMode='public';
function css(){if($('#proCloudCss'))return;const st=document.createElement('style');st.id='proCloudCss';st.textContent=`.cloudBox{margin-top:10px;border:1px solid #bbf7d0;background:#f0fdf4;border-radius:12px;padding:10px}.cloudHead{display:flex;justify-content:space-between;gap:8px;align-items:center}.cloudHead b{color:#065f46}.cloudMeta{font-size:12px;color:#166534;line-height:1.55;margin-top:6px;word-break:break-word}.cloudBtns{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:10px}.cloudBtn{height:38px;border-radius:10px;font-weight:950;border:1px solid #087b34}.cloudBtn.main{background:#087b34;color:#fff}.cloudBtn.sub{background:#fff;color:#087b34}.cloudBtn:disabled{opacity:.55}.cloudWarn{border-color:#fed7aa;background:#fff7ed}.cloudWarn .cloudMeta{color:#9a3412}.cloudOk{color:#15803d;font-weight:950}@media(max-width:520px){.cloudBtns{grid-template-columns:1fr}}`;document.head.appendChild(st)}
function cfg(){let c={};try{c=JSON.parse(localStorage.getItem('doit-cloud-cfg')||'{}')}catch{}let url=T(c.url).replace(/\/$/,'');if(!url||/xxx|your-project|example/i.test(url))url=DEFAULT_URL;return{url,key:T(c.key)}}
function dateLabel(s){try{return new Date(s).toLocaleString('th-TH')}catch{return s||'-'}}
function setMsg(s){const m=$('#cloudProMsg');if(m)m.innerHTML=s}
function ui(){css();const uploadCard=document.querySelector('#upload .card');if(!uploadCard||$('#proCloudBox'))return;const box=document.createElement('div');box.id='proCloudBox';box.className='cloudBox';box.innerHTML=`<div class="cloudHead"><b>ไฟล์ DOIT ล่าสุดจากระบบกลาง</b><span id="cloudProState" class="cloudOk">รอตรวจสอบ</span></div><div id="cloudProMsg" class="cloudMeta">กด “ตรวจไฟล์ล่าสุด” เพื่อดูไฟล์ที่หัวหน้าอัปโหลด</div><div class="cloudBtns"><button class="cloudBtn sub" id="cloudCheckBtn" type="button">ตรวจไฟล์ล่าสุด</button><button class="cloudBtn main" id="cloudLoadBtn" type="button">โหลดไฟล์ล่าสุดจาก Cloud</button></div>`;uploadCard.appendChild(box);$('#cloudCheckBtn').onclick=check;$('#cloudLoadBtn').onclick=loadLatest;setTimeout(check,500)}
async function publicFetch(mode='meta'){const r=await fetch(PUBLIC_ACTIVE_ENDPOINT+'?mode='+encodeURIComponent(mode),{headers:{Accept:'application/json'}});const text=await r.text();if(!r.ok)throw Error(text||('HTTP '+r.status));try{return JSON.parse(text)}catch{throw Error('อ่านข้อมูลกลางไม่สำเร็จ')}}
async function sbFetch(path,opt={}){const c=cfg();if(!c.key)throw Error('ยังไม่มี anon key ในเครื่องนี้');const r=await fetch(c.url+path,{...opt,headers:{apikey:c.key,Authorization:'Bearer '+c.key,...(opt.headers||{})}});const text=await r.text();if(!r.ok)throw Error(text||('HTTP '+r.status));try{return JSON.parse(text)}catch{return text}}
function showActive(a,mode){const st=$('#cloudProState'),box=$('#proCloudBox');if(box)box.classList.remove('cloudWarn');if(st)st.textContent='พร้อม';setMsg(`ไฟล์: <b>${a.file_name}</b><br>โหมด: <b>${a.data_path?'JSON/index เบา':'Excel fallback'}</b><br>แหล่งโหลด: <b>${mode==='public'?'ระบบกลางพร้อมใช้':'config ในเครื่อง'}</b><br>อัปโหลด: ${dateLabel(a.uploaded_at)}<br>แถว: ${Number(a.row_count||0).toLocaleString('th-TH')} · ร้าน: ${Number(a.store_count||0).toLocaleString('th-TH')} · PS: ${Number(a.ps_count||0).toLocaleString('th-TH')} · Telesale bills: ${Number(a.telesale_bill_count||0).toLocaleString('th-TH')}`)}
async function check(){try{const st=$('#cloudProState');if(st)st.textContent='กำลังตรวจ';try{const packet=await publicFetch('meta');active=packet.active;publicPacket=null;sourceMode='public';if(!active)throw Error('no_active');showActive(active,'public');return active}catch(pubErr){const rows=await sbFetch('/rest/v1/doit_versions?select=id,file_name,file_size,storage_path,data_path,data_status,data_schema_version,row_count,store_count,ps_count,telesale_bill_count,status,is_active,uploaded_at&is_active=eq.true&order=uploaded_at.desc&limit=1');active=Array.isArray(rows)?rows[0]:null;publicPacket=null;sourceMode='legacy';if(!active){const box=$('#proCloudBox');if(box)box.classList.add('cloudWarn');setMsg('ยังไม่มีไฟล์ที่ตั้งเป็นล่าสุดในระบบกลาง ให้ไปหน้า Admin แล้วกด “อัปโหลด JSON + ตั้งล่าสุด”');if(st)st.textContent='ไม่มีไฟล์';return null}showActive(active,'legacy');return active}}catch(e){const box=$('#proCloudBox');if(box)box.classList.add('cloudWarn');const st=$('#cloudProState');if(st)st.textContent='ผิดพลาด';setMsg('ตรวจ Cloud ไม่สำเร็จ: '+(e.message||e));return null}}
function loadScript(src){return new Promise((resolve,reject)=>{if(document.querySelector(`script[src="${src}"]`))return resolve();const s=document.createElement('script');s.src=src;s.onload=resolve;s.onerror=()=>reject(Error('โหลด '+src+' ไม่สำเร็จ'));document.head.appendChild(s)})}
async function ensureJsonApp(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.version!=='v265')await loadScript('/assets/pro-json-app-v265.js?v=265')}
async function downloadPath(path,asJson=false){const c=cfg();const p=String(path||'').split('/').map(encodeURIComponent).join('/');const r=await fetch(`${c.url}/storage/v1/object/doit-files/${p}`,{headers:{apikey:c.key,Authorization:'Bearer '+c.key}});if(!r.ok)throw Error(await r.text()||('ดาวน์โหลดไม่ได้ HTTP '+r.status));return asJson?await r.json():await r.blob()}
async function loadExcelFallback(){const blob=await downloadPath(active.storage_path,false);const file=new File([blob],active.file_name||'doit-latest.xlsx',{type:blob.type||'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',lastModified:Date.now()});const input=$('#file');if(!input)throw Error('ไม่พบ input file ในหน้า Pro');const dt=new DataTransfer();dt.items.add(file);input.files=dt.files;$('#fileLabel')&&( $('#fileLabel').textContent=file.name );input.dispatchEvent(new Event('change',{bubbles:true}));setMsg(`โหลด Excel fallback แล้ว กำลังอ่านไฟล์ในหน้า Pro...<br><b>${active.file_name}</b>`)}
async function loadLatest(){if(loading)return;loading=true;const btn=$('#cloudLoadBtn');try{if(btn){btn.disabled=true;btn.textContent='กำลังโหลดจาก Cloud...'}if(!active)await check();if(!active)throw Error('ยังไม่มี active version');if(active.data_path){await ensureJsonApp();setMsg(`กำลังโหลด JSON/index เบา...<br><b>${active.file_name}</b>`);let data=null;if(sourceMode==='public'){const packet=publicPacket||await publicFetch('data');publicPacket=packet;active=packet.active||active;if(packet.mode!=='json'||!packet.payload)throw Error('ระบบกลางยังไม่มี JSON payload');data=packet.payload}else{data=await downloadPath(active.data_path,true)}window.DOIT_JSON_APP.load(data,active);setMsg(`โหลด JSON/index สำเร็จ ไม่ต้องอ่าน Excel ใหญ่<br><b>${active.file_name}</b>`)}else{setMsg(`ไม่มี JSON/index กำลัง fallback ไป Excel...<br><b>${active.file_name}</b>`);await loadExcelFallback()}}catch(e){setMsg('โหลด Cloud ไม่สำเร็จ: '+(e.message||e));const box=$('#proCloudBox');if(box)box.classList.add('cloudWarn')}finally{loading=false;if(btn){btn.disabled=false;btn.textContent='โหลดไฟล์ล่าสุดจาก Cloud'}}}
function boot(){ui();setTimeout(ui,700);setTimeout(ui,1600)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();
